import pymongo as py


def where_mongo():
    mongo = py.MongoClient('127.0.0.1', 27017)

    mydb = mongo['mydatabase']

    mycol = mydb['items']

    print("Number of entries with a price lower than 500: " + str(
        len(list(mycol.find({"price": {"$lt": 500}})))))


where_mongo()